// SECTION 2: CONFIG
// ============================================================
const TOPICS = ["Jurisdiction","Choice of Court","Foreign Judgments","Choice - Technique","Choice - Contracts","Choice - Tort","Choice - Property","Exclusion of Foreign Law"];
const TYPES  = ["Dicey Illustration","Case","Principle","Statute"];
const TOPIC_COLORS = {"Jurisdiction":"#60a5fa","Choice of Court":"#f472b6","Foreign Judgments":"#a78bfa","Choice - Technique":"#34d399","Choice - Contracts":"#f5a623","Choice - Tort":"#e94560","Choice - Property":"#06d6a0","Exclusion of Foreign Law":"#c084fc"};
const TYPE_COLORS  = {"Dicey Illustration":"#94a3b8","Case":"#fbbf24","Principle":"#38bdf8","Statute":"#4ade80"};
const STORAGE_SCORES_KEY = "col-scores-v1";
const STORAGE_GIST_KEY = "col-gist-v1";
const GIST_FILENAME = "col-flashcards-data.json";
const GIST_TOKEN = import.meta.env.VITE_GIST_TOKEN||"";

async function gistLoad(token){
  try{
    const r=await fetch("https://api.github.com/gists",{headers:{"Authorization":`Bearer ${token}`,"Accept":"application/vnd.github+json"}});
    const list=await r.json();
    const g=list.find(x=>x.files&&x.files[GIST_FILENAME]);
    if(!g)return null;
    const full=await fetch(`https://api.github.com/gists/${g.id}`,{headers:{"Authorization":`Bearer ${token}`}});
    const data=await full.json();
    const content=data.files[GIST_FILENAME]?.content;
    return content?{id:g.id,...JSON.parse(content)}:null;
  }catch{return null;}
}

async function gistSave(token,gistId,payload){
  try{
    const body={files:{[GIST_FILENAME]:{content:JSON.stringify(payload)}}};
    if(gistId){
      await fetch(`https://api.github.com/gists/${gistId}`,{method:"PATCH",headers:{"Authorization":`Bearer ${token}`,"Content-Type":"application/json"},body:JSON.stringify(body)});
      return gistId;
    }else{
      const r=await fetch("https://api.github.com/gists",{method:"POST",headers:{"Authorization":`Bearer ${token}`,"Content-Type":"application/json"},body:JSON.stringify({...body,description:"CoL Flashcards Data",public:false})});
      const data=await r.json();
      return data.id||null;
    }
  }catch{return gistId;}
}

// ============================================================
// SECTION 3: COMPONENTS + APP
// ============================================================
function shuffle(arr){const a=[...arr];for(let i=a.length-1;i>0;i--){const j=Math.floor(Math.random()*(i+1));[a[i],a[j]]=[a[j],a[i]];}return a;}
function weightedShuffle(arr,weightFn){return [...arr].map(item=>({item,key:Math.random()**(1/Math.max(weightFn(item),0.001))})).sort((a,b)=>b.key-a.key).map(({item})=>item);}
function getTopics(c){return c.tags.filter(t=>t.startsWith("topic:")).map(t=>t.slice(6));}
function getTypes(c){return c.tags.filter(t=>t.startsWith("type:")).map(t=>t.slice(5));}
function isAiScenario(c){return (c.flags||[]).includes("ai-scenario");}

function Tag({label,color,small}){
  return <span style={{background:color+"22",color,border:`1px solid ${color}55`,fontSize:small?"10px":"11px",padding:small?"2px 7px":"3px 9px",borderRadius:"3px",whiteSpace:"nowrap"}}>{label}</span>;
}

function RobotIcon({filled,color}){
  const fg = filled ? color : "#2a2a3a";
  const dot = filled ? "#000000" : "#2a2a3a";
  return(
    <svg width="20" height="20" viewBox="0 0 24 24" fill={filled ? color : "none"} stroke={fg} strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" style={{flexShrink:0}} title={filled?"AI-generated scenario":"Verified content"}>
      <line x1="12" y1="2" x2="12" y2="5" stroke={fg}/>
      <circle cx="12" cy="2" r="1" fill={fg} stroke={fg}/>
      <rect x="5" y="5" width="14" height="10" rx="2"/>
      <circle cx="9" cy="10" r="1.5" fill={dot} stroke={dot}/>
      <circle cx="15" cy="10" r="1.5" fill={dot} stroke={dot}/>
      <path d="M9 13h6" stroke={fg}/>
      <line x1="12" y1="15" x2="12" y2="17" stroke={fg}/>
      <rect x="7" y="17" width="10" height="5" rx="1"/>
      <line x1="7" y1="19" x2="4" y2="19" stroke={fg}/>
      <line x1="17" y1="19" x2="20" y2="19" stroke={fg}/>
    </svg>
  );
}

async function gradeAnswer(question,userAnswer,correctAnswer){
  try{
    const res=await fetch("https://api.anthropic.com/v1/messages",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({model:"claude-sonnet-4-20250514",max_tokens:300,messages:[{role:"user",content:`You are grading a conflict of laws flashcard answer.\n\nQuestion: ${question}\nModel Answer: ${correctAnswer}\nStudent's Answer: ${userAnswer}\n\nRules:\n- "yes"/"no" answers: mark correct or incorrect on merits only, do not penalise brevity\n- "partial" only for genuinely incomplete substantive answers\n- Feedback: one sentence explaining the correct legal position\n\nJSON only: {"result":"correct"|"partial"|"incorrect","feedback":"..."}`}]})});
    const data=await res.json();
    const text=data.content?.find(b=>b.type==="text")?.text||"";
    return JSON.parse(text.replace(/```json|```/g,"").trim());
  }catch{return{result:"incorrect",feedback:"Could not grade — check manually."};}
}

export default function App(){
  const [scores,setScores]=useState({});
  const [flags,setFlags]=useState([]);
  const [hidden,setHidden]=useState([]);
  const [edits,setEdits]=useState({});
  const [gistId,setGistId]=useState(null);
  const [syncing,setSyncing]=useState(false);
  const [editingCard,setEditingCard]=useState(null);
  const [loaded,setLoaded]=useState(false);
  const [view,setView]=useState("study");
  const [deck,setDeck]=useState([]);
  const [idx,setIdx]=useState(0);
  const [flipped,setFlipped]=useState(false);
  const [userAnswer,setUserAnswer]=useState("");
  const [grading,setGrading]=useState(false);
  const [gradingResult,setGradingResult]=useState(null);
  const [filterTopics,setFilterTopics]=useState([]);
  const [filterTypes,setFilterTypes]=useState([]);
  const [filterFlag,setFilterFlag]=useState("all");
  const [studyMode,setStudyMode]=useState("all");
  const [showFilters,setShowFilters]=useState(false);
  const [sessionCorrect,setSessionCorrect]=useState(0);
  const [sessionTotal,setSessionTotal]=useState(0);
  const [showPendingCopyModal,setShowPendingCopyModal]=useState(false);
  const [jumpToId,setJumpToId]=useState("");
  const [searchQuery,setSearchQuery]=useState("");

  const loadFromStorage=useCallback(async()=>{
    let storedScores={};
    let storedFlags=[];
    let storedHidden=[];
    let storedEdits={};
    let storedGistId=null;
    try{const r=localStorage.getItem(STORAGE_SCORES_KEY);if(r)storedScores=JSON.parse(r);}catch(e){}
    try{const r=localStorage.getItem(STORAGE_GIST_KEY);if(r){const g=JSON.parse(r);storedGistId=g.gistId||null;}}catch(e){}
    setScores(storedScores);
    setGistId(storedGistId);
    const g=await gistLoad(GIST_TOKEN);
    if(g){
      storedFlags=g.flags||[];
      storedHidden=g.hidden||[];
      storedEdits=g.edits||{};
      if(g.scores)storedScores={...storedScores,...g.scores};
      setScores(storedScores);
      setGistId(g.id);
      try{localStorage.setItem(STORAGE_GIST_KEY,JSON.stringify({gistId:g.id}));}catch(e){}
    }
    setFlags(storedFlags);
    setHidden(storedHidden);
    setEdits(storedEdits);
    setLoaded(true);
  },[]);

  useEffect(()=>{loadFromStorage();},[]);

  const syncToGist=useCallback(async(newScores,newFlags,newHidden,newEdits,id)=>{
    if(!GIST_TOKEN)return;
    setSyncing(true);
    const newId=await gistSave(GIST_TOKEN,id,{scores:newScores,flags:newFlags,hidden:newHidden,edits:newEdits});
    if(newId&&newId!==id){setGistId(newId);try{localStorage.setItem(STORAGE_GIST_KEY,JSON.stringify({gistId:newId}));}catch(e){}}
    setSyncing(false);
  },[]);

  useEffect(()=>{
    if(!loaded)return;
    try{localStorage.setItem(STORAGE_SCORES_KEY,JSON.stringify(scores));}catch(e){}
    syncToGist(scores,flags,hidden,edits,gistId);
  },[scores,flags,hidden,edits,loaded]);

  useEffect(()=>{
    if(!loaded)return;
    const baseFilter=c=>{
      if(hidden.includes(c.id))return false;
      if(filterTopics.length>0&&!filterTopics.some(t=>getTopics(c).includes(t)))return false;
      if(filterTypes.length>0&&!filterTypes.some(t=>getTypes(c).includes(t)))return false;
      if(filterFlag==="exclude-ai"&&isAiScenario(c))return false;
      if(filterFlag==="ai-only"&&!isAiScenario(c))return false;
      return true;
    };
    if(studyMode==="flagged"){
      setDeck(shuffle(ALL_CARDS.filter(c=>baseFilter(c)&&flags.includes(c.id))));
    }else if(studyMode==="weak"){
      const weak=ALL_CARDS.filter(c=>{
        if(!baseFilter(c))return false;
        const sc=scores[c.id]||{correct:0,incorrect:0};
        return sc.incorrect>0;
      });
      setDeck(weightedShuffle(weak,c=>{const sc=scores[c.id]||{correct:0,incorrect:0};const t=sc.correct+sc.incorrect;return t>0?sc.incorrect/t:0.5;}));
    }else if(studyMode==="unseen"){
      const all=ALL_CARDS.filter(baseFilter);
      setDeck(weightedShuffle(all,c=>{const sc=scores[c.id]||{correct:0,incorrect:0,seen:0};return 1/((sc.seen||0)+1);}));
    }else{
      setDeck(shuffle(ALL_CARDS.filter(baseFilter)));
    }
    setIdx(0);setFlipped(false);setUserAnswer("");setGradingResult(null);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  },[filterTopics,filterTypes,filterFlag,studyMode,loaded]);

  const getScore=useCallback((id)=>scores[id]||{correct:0,incorrect:0},[scores]);
  const rawCard=deck[Math.min(idx,deck.length-1)]||null;
  const card=rawCard?{...rawCard,...(edits[rawCard.id]||{})}:null;
  const primaryTopic=card?getTopics(card)[0]:null;
  const accentColor=primaryTopic?(TOPIC_COLORS[primaryTopic]||"#a78bfa"):"#a78bfa";
  const cardScore=card?getScore(card.id):{correct:0,incorrect:0};

  const reset=()=>{setFlipped(false);setUserAnswer("");setGradingResult(null);};
  const next=()=>{setIdx(i=>(i+1)%deck.length);reset();};
  const prev=()=>{if(flipped){setFlipped(false);setGradingResult(null);}else{setIdx(i=>(i-1+deck.length)%deck.length);reset();}};

  const updateScore=(id,correct)=>{
    setScores(prev=>{const cur=prev[id]||{correct:0,incorrect:0};return{...prev,[id]:{correct:cur.correct+(correct?1:0),incorrect:cur.incorrect+(!correct?1:0)}};});
    setSessionTotal(t=>t+1);
    if(correct)setSessionCorrect(s=>s+1);
  };

  const handleGrade=async()=>{
    if(!userAnswer.trim())return;
    setGrading(true);
    const result=await gradeAnswer(card.question,userAnswer,card.answer);
    setGradingResult(result);setGrading(false);
    updateScore(card.id,result.result==="correct");
  };

  const handleSelfMark=(correct)=>{updateScore(card.id,correct);next();};
  const markSeen=(id)=>setScores(prev=>{const cur=prev[id]||{correct:0,incorrect:0,seen:0};return{...prev,[id]:{...cur,seen:(cur.seen||0)+1}};});
  const toggleFlag=(id)=>setFlags(f=>f.includes(id)?f.filter(x=>x!==id):[...f,id]);
  const toggleHide=(id)=>setHidden(h=>h.includes(id)?h.filter(x=>x!==id):[...h,id]);
  const saveEdit=(id,q,a)=>{setEdits(e=>({...e,[id]:{question:q,answer:a}}));setEditingCard(null);};

  const totalCorrect=Object.values(scores).reduce((s,sc)=>s+sc.correct,0);
  const totalIncorrect=Object.values(scores).reduce((s,sc)=>s+sc.incorrect,0);

  const pendingEditsEntries=Object.entries(edits);
  const pendingHiddenCards=hidden.map(id=>ALL_CARDS.find(c=>c.id===id)).filter(Boolean);
  const pendingSummary=[
    pendingHiddenCards.length?`HIDDEN CARDS (${pendingHiddenCards.length}):\n${pendingHiddenCards.map(c=>`- Card ${c.id} [${c.number}] ${c.question.slice(0,60)}…`).join("\n")}`:null,
    pendingEditsEntries.length?`EDITED CARDS (${pendingEditsEntries.length}):\n${pendingEditsEntries.map(([id,e])=>{const orig=ALL_CARDS.find(c=>c.id===+id);return`- Card ${id} [${orig?.number}]\n  Q: ${e.question||"(unchanged)"}\n  A: ${e.answer||"(unchanged)"}`;}).join("\n\n")}`:null,
  ].filter(Boolean).join("\n\n")||"No pending changes.";

  const nb=(a)=>({background:a?"#1e1e3a":"transparent",border:`1px solid ${a?"#3a3a5a":"#1e1e2e"}`,color:a?"#a0a0d0":"#555",padding:"7px 16px",borderRadius:"6px",cursor:"pointer",fontSize:"12px",letterSpacing:"2px",textTransform:"uppercase"});
  const fb=(a,c)=>({background:a?c+"22":"transparent",border:`1px solid ${a?c:"#2a2a3a"}`,color:a?c:"#555",padding:"4px 11px",borderRadius:"4px",cursor:"pointer",fontSize:"11px",whiteSpace:"nowrap"});
  const mb=(a)=>({background:a?"#1e1e3a":"transparent",border:`1px solid ${a?"#3a3a5a":"#2a2a3a"}`,color:a?"#a0a0d0":"#444",padding:"4px 11px",borderRadius:"4px",cursor:"pointer",fontSize:"11px"});

  if(!loaded)return(
    <div style={{minHeight:"100vh",background:"#080810",display:"flex",alignItems:"center",justifyContent:"center",fontFamily:"Palatino,serif",color:"#444",fontSize:"14px",letterSpacing:"2px"}}>Loading…</div>
  );

  return(
    <div style={{height:"100dvh",background:"#080810",fontFamily:"'Palatino Linotype',Palatino,serif",color:"#e8e8f0",display:"flex",flexDirection:"column",overflow:"hidden"}}>
      {/* Nav */}
      <div style={{flexShrink:0,display:"flex",alignItems:"center",justifyContent:"space-between",padding:"12px 12px",borderBottom:"1px solid #1a1a2e",background:"#0a0a14"}}>
        <div style={{display:"flex",alignItems:"center",gap:"10px"}}>
          <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 32 32" width="28" height="28" style={{flexShrink:0}}>
            <rect width="32" height="32" rx="6" fill="#13131f"/>
            <text x="16" y="23" textAnchor="middle" fontSize="20" fontFamily="serif" fill="#a78bfa">C</text>
          </svg>
          <div>
            <div style={{fontSize:"10px",letterSpacing:"4px",color:"#444",textTransform:"uppercase"}}>BCL Flashcards</div>
            <div style={{fontSize:"18px",color:"#c8c8e0"}}>Conflict of Laws</div>
          </div>
        </div>
        <div style={{display:"flex",gap:"6px",alignItems:"center"}}>
          {syncing&&<span style={{fontSize:"10px",color:"#444"}}>syncing…</span>}
          {/* Study */}
          <button onClick={()=>setView("study")} title="Study" style={{...nb(view==="study"),padding:"8px 10px"}}>
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"><path d="M12 20h9"/><path d="M16.5 3.5a2.121 2.121 0 0 1 3 3L7 19l-4 1 1-4L16.5 3.5z"/></svg>
          </button>
          {/* Stats */}
          <button onClick={()=>setView("stats")} title="Stats" style={{...nb(view==="stats"),padding:"8px 10px"}}>
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"><path d="M21.21 15.89A10 10 0 1 1 8 2.83"/><path d="M22 12A10 10 0 0 0 12 2v10z"/></svg>
          </button>
          {/* Wrench */}
          <button onClick={()=>setView("manage")} title="Manage" style={{...nb(view==="manage"),padding:"8px 10px"}}>
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"><path d="M14.7 6.3a1 1 0 0 0 0 1.4l1.6 1.6a1 1 0 0 0 1.4 0l3.77-3.77a6 6 0 0 1-7.94 7.94l-6.91 6.91a2.12 2.12 0 0 1-3-3l6.91-6.91a6 6 0 0 1 7.94-7.94l-3.76 3.76z"/></svg>
          </button>
        </div>
      </div>

      {/* STUDY */}
      {view==="study"&&(
        <div style={{flex:1,minHeight:0,display:"flex",flexDirection:"column",padding:"10px 12px 0",gap:"10px",overflow:"hidden"}}>
          {/* Filters — locked, never scrolls */}
          <div style={{flexShrink:0}}>
            <button onClick={()=>setShowFilters(!showFilters)} style={{width:"100%",background:"#0e0e1a",border:"1px solid #1e1e2e",borderRadius:"8px",padding:"10px 16px",cursor:"pointer",display:"flex",justifyContent:"space-between",alignItems:"center",color:"#666",fontSize:"12px",letterSpacing:"2px",textTransform:"uppercase"}}>
              <span>Filters {filterTopics.length>0||filterTypes.length>0||filterFlag!=="all"||studyMode!=="all"?"(active)":""}</span>
              <span style={{fontSize:"14px"}}>{showFilters?"▲":"▼"}</span>
            </button>
            {showFilters&&(
              <div style={{marginTop:"10px",display:"flex",flexDirection:"column",gap:"10px",maxHeight:"38vh",overflowY:"auto"}}>
                <div>
                  <div style={{fontSize:"10px",letterSpacing:"3px",color:"#333",textTransform:"uppercase",marginBottom:"7px"}}>Topic</div>
                  <div style={{display:"flex",gap:"5px",flexWrap:"wrap"}}>
                    <button onClick={()=>setFilterTopics([])} style={fb(filterTopics.length===0,"#888")}>All</button>
                    {TOPICS.map(t=><button key={t} onClick={()=>setFilterTopics(prev=>prev.includes(t)?prev.filter(x=>x!==t):[...prev,t])} style={fb(filterTopics.includes(t),TOPIC_COLORS[t])}>{t}</button>)}
                  </div>
                </div>
                <div style={{display:"flex",gap:"10px",flexWrap:"wrap",alignItems:"flex-start"}}>
                  <div style={{flex:1,minWidth:"150px"}}>
                    <div style={{fontSize:"10px",letterSpacing:"3px",color:"#333",textTransform:"uppercase",marginBottom:"7px"}}>Type</div>
                    <div style={{display:"flex",gap:"5px",flexWrap:"wrap"}}>
                      <button onClick={()=>setFilterTypes([])} style={fb(filterTypes.length===0,"#888")}>All</button>
                      {TYPES.map(t=><button key={t} onClick={()=>setFilterTypes(prev=>prev.includes(t)?prev.filter(x=>x!==t):[...prev,t])} style={fb(filterTypes.includes(t),TYPE_COLORS[t])}>{t}</button>)}
                    </div>
                  </div>
                  <div>
                    <div style={{fontSize:"10px",letterSpacing:"3px",color:"#333",textTransform:"uppercase",marginBottom:"7px"}}>AI Scenarios</div>
                    <div style={{display:"flex",gap:"5px"}}>
                      {[["all","Include"],["exclude-ai","Exclude"],["ai-only","Only"]].map(([m,l])=>(
                        <button key={m} onClick={()=>setFilterFlag(m)} style={mb(filterFlag===m)}>{l}</button>
                      ))}
                    </div>
                  </div>
                  <div>
                    <div style={{fontSize:"10px",letterSpacing:"3px",color:"#333",textTransform:"uppercase",marginBottom:"7px"}}>Mode</div>
                    <div style={{display:"flex",gap:"5px"}}>
                      {[["all","All"],["weak","Weak"],["unseen","Unseen"],["flagged","Flagged"]].map(([m,l])=>(
                        <button key={m} onClick={()=>setStudyMode(m)} style={mb(studyMode===m)}>{l}</button>
                      ))}
                    </div>
                  </div>
                </div>
              </div>
            )}
          </div>

          {deck.length===0?(
            <div style={{color:"#444",fontSize:"14px",marginTop:"60px"}}>No cards match this filter.</div>
          ):card&&(<>
            {/* Progress panel — locked */}
            <div style={{flexShrink:0,background:"#0e0e1a",border:"1px solid #1e1e2e",borderRadius:"10px",padding:"12px 16px",display:"flex",alignItems:"center",justifyContent:"space-between",gap:"12px",flexWrap:"wrap"}}>
              <div style={{display:"flex",flexDirection:"column",alignItems:"center",minWidth:"48px"}}>
                <span style={{fontSize:"18px",color:"#c8c8e0",lineHeight:1}}>{Math.min(idx,deck.length-1)+1}<span style={{fontSize:"13px",color:"#444"}}>/{deck.length}</span></span>
                <div style={{display:"flex",gap:"4px",alignItems:"center",marginTop:"2px"}}>
                  <span style={{fontSize:"9px",color:"#333",letterSpacing:"2px",textTransform:"uppercase"}}>card</span>
                  {flags.includes(rawCard.id)&&<svg width="9" height="9" viewBox="0 0 24 24" fill="#f5a623" stroke="#f5a623" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M4 15s1-1 4-1 5 2 8 2 4-1 4-1V3s-1 1-4 1-5-2-8-2-4 1-4 1z"/><line x1="4" y1="22" x2="4" y2="15"/></svg>}
                </div>
              </div>
              <div style={{display:"flex",gap:"6px",flexWrap:"wrap",flex:1,justifyContent:"center"}}>
                {getTopics(card).map(t=><Tag key={t} label={t} color={TOPIC_COLORS[t]||"#a78bfa"}/>)}
                {getTypes(card).map(t=><Tag key={t} label={t} color={TYPE_COLORS[t]||"#94a3b8"}/>)}
              </div>
              <div style={{display:"flex",gap:"16px",alignItems:"center"}}>
                <div style={{display:"flex",flexDirection:"column",alignItems:"center"}}>
                  <span style={{fontSize:"11px",color:"#444",letterSpacing:"2px",textTransform:"uppercase",marginBottom:"4px"}}>This card</span>
                  <div style={{display:"flex",gap:"10px"}}>
                    <span style={{fontSize:"16px",color:"#06d6a0"}}>✓ {cardScore.correct}</span>
                    <span style={{fontSize:"16px",color:"#e94560"}}>✗ {cardScore.incorrect}</span>
                  </div>
                </div>
                {sessionTotal>0&&(
                  <div style={{display:"flex",flexDirection:"column",alignItems:"center",borderLeft:"1px solid #1e1e2e",paddingLeft:"16px"}}>
                    <span style={{fontSize:"11px",color:"#444",letterSpacing:"2px",textTransform:"uppercase",marginBottom:"4px"}}>Session</span>
                    <span style={{fontSize:"16px",color:"#a0a0d0"}}>{sessionCorrect}/{sessionTotal}</span>
                  </div>
                )}
              </div>
            </div>

            {/* Scroll wrapper — flex:1 takes remaining space, clips + scrolls if needed */}
            <div style={{flex:1,minHeight:0,overflowY:"auto",paddingBottom:flipped?"146px":"82px"}}>
              {/* Card — only as tall as its content */}
              <div style={{borderRadius:"12px",boxShadow:"0 8px 32px rgba(0,0,0,0.5)",border:`1px solid ${accentColor}80`,background:"#0e0e1a",padding:"16px"}}>
                <p style={{fontSize:"15px",lineHeight:1.8,color:"#d0d0e8",margin:"0 0 20px"}}>{flipped?card.answer:card.question}</p>
                {flipped&&(<>
                  <div style={{borderTop:`1px solid ${accentColor}30`,paddingTop:"16px",marginBottom:"16px"}}>
                    <span style={{color:accentColor,fontSize:"10px",letterSpacing:"3px",textTransform:"uppercase"}}>Key Principle</span>
                    <p style={{color:"#9090b0",fontSize:"13px",fontStyle:"italic",lineHeight:1.7,margin:"8px 0 0"}}>{card.keyPrinciple}</p>
                  </div>
                  <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",borderTop:"1px solid #1a1a28",paddingTop:"12px"}}>
                    <div style={{display:"flex",alignItems:"center",gap:"8px"}}>
                      <RobotIcon filled={isAiScenario(card)} color={accentColor}/>
                      {flags.includes(rawCard.id)&&<svg width="14" height="14" viewBox="0 0 24 24" fill="#f5a623" stroke="#f5a623" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M4 15s1-1 4-1 5 2 8 2 4-1 4-1V3s-1 1-4 1-5-2-8-2-4 1-4 1z"/><line x1="4" y1="22" x2="4" y2="15"/></svg>}
                      {card.subtopic&&<span style={{fontSize:"10px",color:"#444",letterSpacing:"1px",textTransform:"uppercase"}}>{card.subtopic}</span>}
                    </div>
                    {card.reference&&<span style={{fontSize:"11px",color:"#555",fontStyle:"italic"}}>{card.reference}</span>}
                  </div>
                </>)}
              </div>
            </div>
            <div style={{position:"fixed",bottom:0,left:0,right:0,background:"#0a0a14",borderTop:"1px solid #1a1a2e",zIndex:100}}>
              {flipped&&(
                <div style={{display:"flex",gap:"6px",padding:"8px 12px",alignItems:"center"}}>
                  <button onClick={()=>toggleFlag(rawCard.id)} title="Flag" style={{background:flags.includes(rawCard.id)?"#f5a62320":"transparent",border:`1px solid ${flags.includes(rawCard.id)?"#f5a62350":"#1e1e2e"}`,color:flags.includes(rawCard.id)?"#f5a623":"#444",padding:"8px 10px",borderRadius:"8px",cursor:"pointer",flexShrink:0}}>
                    <svg width="14" height="14" viewBox="0 0 24 24" fill={flags.includes(rawCard.id)?"#f5a623":"none"} stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M4 15s1-1 4-1 5 2 8 2 4-1 4-1V3s-1 1-4 1-5-2-8-2-4 1-4 1z"/><line x1="4" y1="22" x2="4" y2="15"/></svg>
                  </button>
                  <button onClick={()=>setEditingCard(rawCard)} title="Edit" style={{background:"transparent",border:"1px solid #1e1e2e",color:"#444",padding:"8px 10px",borderRadius:"8px",cursor:"pointer",flexShrink:0}}>
                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"/><path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"/></svg>
                  </button>
                  <button onClick={()=>toggleHide(rawCard.id)} title="Hide" style={{background:hidden.includes(rawCard.id)?"#88888820":"transparent",border:`1px solid ${hidden.includes(rawCard.id)?"#88888850":"#1e1e2e"}`,color:hidden.includes(rawCard.id)?"#aaa":"#444",padding:"8px 10px",borderRadius:"8px",cursor:"pointer",flexShrink:0}}>
                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M17.94 17.94A10.07 10.07 0 0 1 12 20c-7 0-11-8-11-8a18.45 18.45 0 0 1 5.06-5.94"/><path d="M9.9 4.24A9.12 9.12 0 0 1 12 4c7 0 11 8 11 8a18.5 18.5 0 0 1-2.16 3.19"/><line x1="1" y1="1" x2="23" y2="23"/></svg>
                  </button>
                  <span style={{marginLeft:"auto",fontSize:"11px",color:"#333",letterSpacing:"1px"}}>Card {rawCard.id}</span>
                </div>
              )}
              <div style={{display:"flex",gap:"6px",padding:flipped?"0 12px calc(12px + env(safe-area-inset-bottom))":"8px 12px calc(8px + env(safe-area-inset-bottom))"}}>
                {flipped?(
                  <>
                    <button onClick={prev} style={{background:"transparent",border:"1px solid #1e1e2e",color:"#444",padding:"12px 10px",borderRadius:"8px",cursor:"pointer",fontSize:"13px",flexShrink:0}}>←</button>
                    <button onClick={()=>handleSelfMark(false)} style={{background:"#e9456015",border:"1px solid #e9456050",color:"#e94560",padding:"12px 0",borderRadius:"8px",cursor:"pointer",fontSize:"13px",flex:1}}>✗ Wrong</button>
                    <button onClick={()=>handleSelfMark(true)} style={{background:"#06d6a015",border:"1px solid #06d6a050",color:"#06d6a0",padding:"12px 0",borderRadius:"8px",cursor:"pointer",fontSize:"13px",flex:1}}>✓ Right</button>
                    <button onClick={next} style={{background:"transparent",border:"1px solid #1e1e2e",color:"#444",padding:"12px 10px",borderRadius:"8px",cursor:"pointer",fontSize:"13px",flexShrink:0}}>→</button>
                  </>
                ):(
                  <>
                    <button onClick={next} style={{background:"transparent",border:"1px solid #1e1e2e",color:"#444",padding:"12px 16px",borderRadius:"8px",cursor:"pointer",fontSize:"13px",flexShrink:0}}>Skip →</button>
                    <button onClick={()=>{setFlipped(true);markSeen(rawCard.id);}} style={{background:accentColor,border:"none",color:"#000",padding:"12px 0",borderRadius:"8px",cursor:"pointer",fontSize:"13px",fontWeight:"bold",flex:1}}>Reveal Answer</button>
                  </>
                )}
              </div>
            </div>
          </>)}
        </div>
      )}

      {/* STATS */}
      {view==="stats"&&(
        <div style={{flex:1,padding:"14px 12px",maxWidth:"100%",margin:"0 auto",width:"100%",overflowY:"auto"}}>
          <h2 style={{color:"#c8c8e0",fontWeight:400,marginBottom:"14px",fontSize:"18px"}}>Your Performance</h2>
          <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:"8px",marginBottom:"16px"}}>
            {[["Total Cards",ALL_CARDS.length,"#a0a0d0"],["Correct",totalCorrect,"#06d6a0"],["Incorrect",totalIncorrect,"#e94560"]].map(([l,v,c])=>(
              <div key={l} style={{background:"#0e0e1a",border:"1px solid #1e1e2e",borderRadius:"10px",padding:"12px 8px",textAlign:"center"}}>
                <div style={{fontSize:"22px",color:c}}>{v}</div>
                <div style={{fontSize:"10px",color:"#444",letterSpacing:"1px",textTransform:"uppercase",marginTop:"4px"}}>{l}</div>
              </div>
            ))}
          </div>
          {["By Topic","By Type"].map(section=>{
            const items=section==="By Topic"?TOPICS:TYPES;
            const colorMap=section==="By Topic"?TOPIC_COLORS:TYPE_COLORS;
            const filterFn=section==="By Topic"?(c,t)=>getTopics(c).includes(t):(c,t)=>getTypes(c).includes(t);
            return(
              <div key={section} style={{marginBottom:"28px"}}>
                <div style={{color:"#444",fontSize:"11px",letterSpacing:"3px",textTransform:"uppercase",marginBottom:"12px"}}>{section}</div>
                <div style={{display:"flex",flexDirection:"column",gap:"8px"}}>
                  {items.map(item=>{
                    const tc=ALL_CARDS.filter(c=>filterFn(c,item));
                    if(!tc.length)return null;
                    const correct=tc.reduce((s,c)=>s+(scores[c.id]?.correct||0),0);
                    const total=correct+tc.reduce((s,c)=>s+(scores[c.id]?.incorrect||0),0);
                    const pct=total>0?Math.round((correct/total)*100):0;
                    const color=colorMap[item];
                    return(
                      <div key={item} style={{background:"#0e0e1a",border:"1px solid #1e1e2e",borderRadius:"10px",padding:"10px 12px",minWidth:0,overflow:"hidden"}}>
                        <div style={{display:"flex",justifyContent:"space-between",marginBottom:"6px",gap:"8px"}}>
                          <span style={{color,fontSize:"12px",minWidth:0,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{item}</span>
                          <span style={{color:"#555",fontSize:"11px",flexShrink:0}}>{tc.length} · {pct}%</span>
                        </div>
                        <div style={{height:"3px",background:"#1e1e2e",borderRadius:"2px"}}>
                          <div style={{height:"100%",width:`${pct}%`,background:color,borderRadius:"2px",transition:"width 0.5s"}}/>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            );
          })}
          <button onClick={()=>setScores({})} style={{background:"transparent",border:"1px solid #2a2a1a",color:"#555",padding:"10px 20px",borderRadius:"8px",cursor:"pointer",fontSize:"12px"}}>Reset All Scores</button>
        </div>
      )}

      {/* MANAGE */}
      {view==="manage"&&(()=>{
        const pendingEdits=pendingEditsEntries;
        const pendingHidden=pendingHiddenCards;
        const flaggedCards=flags.map(id=>ALL_CARDS.find(c=>c.id===id)).filter(Boolean);
        return(
        <div style={{flex:1,padding:"14px 12px",width:"100%",display:"flex",flexDirection:"column",gap:"14px",overflowY:"auto"}}>
          {/* Jump to Card */}
          <div style={{background:"#0e0e1a",border:"1px solid #1e1e2e",borderRadius:"10px",padding:"14px"}}>
            <div style={{fontSize:"11px",letterSpacing:"2px",color:"#444",textTransform:"uppercase",marginBottom:"10px"}}>Jump to Card</div>
            <div style={{display:"flex",gap:"8px"}}>
              <input value={jumpToId} onChange={e=>setJumpToId(e.target.value)} placeholder="Card ID (e.g. 42)" type="number" min="1" style={{flex:1,background:"#080810",border:"1px solid #2a2a3a",color:"#d0d0e8",borderRadius:"6px",padding:"8px 10px",fontSize:"13px",fontFamily:"inherit",outline:"none"}}/>
              <button onClick={()=>{
                const id=parseInt(jumpToId);
                if(!id)return;
                const found=deck.findIndex(c=>c.id===id);
                if(found>=0){setIdx(found);setFlipped(false);setView("study");}
                else{const inAll=ALL_CARDS.find(c=>c.id===id);if(inAll){setJumpToId("");alert(`Card ${id} is not in the current deck (may be filtered or hidden).`);}}
              }} style={{background:"#a78bfa20",border:"1px solid #a78bfa40",color:"#a78bfa",padding:"8px 16px",borderRadius:"6px",cursor:"pointer",fontSize:"12px"}}>Go</button>
            </div>
          </div>

          {/* Search Cards */}
          <div style={{background:"#0e0e1a",border:"1px solid #1e1e2e",borderRadius:"10px",padding:"14px"}}>
            <div style={{fontSize:"11px",letterSpacing:"2px",color:"#444",textTransform:"uppercase",marginBottom:"10px"}}>Search Cards</div>
            <input value={searchQuery} onChange={e=>setSearchQuery(e.target.value)} placeholder="Search questions and answers…" style={{width:"100%",background:"#080810",border:"1px solid #2a2a3a",color:"#d0d0e8",borderRadius:"6px",padding:"8px 10px",fontSize:"13px",fontFamily:"inherit",outline:"none"}}/>
            {searchQuery.trim()&&(
              <div style={{display:"flex",flexDirection:"column",gap:"6px",marginTop:"10px",maxHeight:"240px",overflowY:"auto"}}>
                {ALL_CARDS.filter(c=>{
                  const q=searchQuery.toLowerCase();
                  return c.question.toLowerCase().includes(q)||c.answer.toLowerCase().includes(q)||(c.keyPrinciple||"").toLowerCase().includes(q);
                }).slice(0,30).map(c=>{
                  const inDeck=deck.findIndex(d=>d.id===c.id);
                  return(
                    <div key={c.id} style={{display:"flex",justifyContent:"space-between",alignItems:"center",gap:"8px",padding:"6px 0",borderBottom:"1px solid #1a1a28"}}>
                      <div style={{flex:1,minWidth:0}}>
                        <span style={{fontSize:"10px",color:"#555",letterSpacing:"1px"}}>Card {c.id}</span>
                        <p style={{fontSize:"12px",color:"#888",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",margin:"2px 0 0"}}>{c.question.slice(0,70)}{c.question.length>70?"…":""}</p>
                      </div>
                      <button onClick={()=>{
                        if(inDeck>=0){setIdx(inDeck);setFlipped(false);setView("study");}
                        else{alert(`Card ${c.id} is not in the current deck.`);}
                      }} style={{background:"transparent",border:"1px solid #2a2a3a",color:inDeck>=0?"#a0a0d0":"#444",padding:"4px 10px",borderRadius:"4px",cursor:"pointer",fontSize:"11px",flexShrink:0}}>{inDeck>=0?"Go":"—"}</button>
                    </div>
                  );
                })}
              </div>
            )}
          </div>

          {/* GitHub Gist Sync */}
          <div style={{background:"#0e0e1a",border:"1px solid #1e1e2e",borderRadius:"10px",padding:"14px"}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:"8px"}}>
              <div style={{fontSize:"11px",letterSpacing:"2px",color:"#444",textTransform:"uppercase"}}>GitHub Sync</div>
              <span style={{color:syncing?"#a78bfa":"#06d6a0",fontSize:"10px"}}>{syncing?"syncing…":"● live"}</span>
            </div>
            <p style={{fontSize:"11px",color:"#444",lineHeight:1.5,margin:0}}>Scores, flags, hidden cards, and edits sync automatically to a private GitHub Gist on every change.</p>
            <button onClick={()=>syncToGist(scores,flags,hidden,edits,gistId)} style={{marginTop:"10px",background:"#a78bfa20",border:"1px solid #a78bfa40",color:"#a78bfa",padding:"8px 16px",borderRadius:"6px",cursor:"pointer",fontSize:"12px",width:"100%"}}>Force Sync Now</button>
          </div>

          {/* Flagged */}
          {flaggedCards.length>0&&(
          <div style={{background:"#0e0e1a",border:"1px solid #f5a62330",borderRadius:"10px",padding:"14px"}}>
            <div style={{fontSize:"11px",letterSpacing:"2px",color:"#f5a623",textTransform:"uppercase",marginBottom:"10px"}}>Flagged for Review ({flaggedCards.length})</div>
            <div style={{display:"flex",flexDirection:"column",gap:"6px"}}>
              {flaggedCards.map(c=>(
                <div key={c.id} style={{display:"flex",justifyContent:"space-between",alignItems:"center",gap:"8px"}}>
                  <span style={{fontSize:"12px",color:"#888",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",flex:1}}>Card {c.id} — {c.question.slice(0,50)}…</span>
                  <button onClick={()=>toggleFlag(c.id)} style={{background:"transparent",border:"1px solid #2a2a3a",color:"#555",padding:"4px 8px",borderRadius:"4px",cursor:"pointer",fontSize:"11px",flexShrink:0}}>Unflag</button>
                </div>
              ))}
            </div>
          </div>
          )}

          {/* Pending Changes */}
          <div style={{background:"#0e0e1a",border:"1px solid #1e1e2e",borderRadius:"10px",padding:"14px"}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:"10px",gap:"8px"}}>
              <div style={{fontSize:"11px",letterSpacing:"2px",color:"#444",textTransform:"uppercase"}}>Edited Cards ({pendingEdits.length})</div>
              <button onClick={()=>setShowPendingCopyModal(true)} style={{background:"#a78bfa20",border:"1px solid #a78bfa40",color:"#a78bfa",padding:"5px 12px",borderRadius:"6px",cursor:"pointer",fontSize:"11px",flexShrink:0}}>Copy Pending Changes</button>
            </div>
            {pendingEdits.length===0
              ? <p style={{fontSize:"12px",color:"#444"}}>No edited cards.</p>
              : <div style={{display:"flex",flexDirection:"column",gap:"8px"}}>
                  {pendingEdits.map(([id,e])=>{
                    const orig=ALL_CARDS.find(c=>c.id===+id);
                    if(!orig)return null;
                    return(
                      <div key={id} style={{background:"#080810",borderRadius:"8px",padding:"10px",border:"1px solid #2a2a3a"}}>
                        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:"8px",gap:"8px"}}>
                          <span style={{fontSize:"11px",color:"#a0a0d0",letterSpacing:"1px"}}>Card {id} — {orig.number}</span>
                          <button onClick={()=>setEdits(ev=>{const n={...ev};delete n[+id];return n;})} style={{background:"transparent",border:"1px solid #2a2a3a",color:"#e94560",padding:"3px 8px",borderRadius:"4px",cursor:"pointer",fontSize:"11px",flexShrink:0}}>Restore Original</button>
                        </div>
                        {e.question&&(
                          <div style={{marginBottom:"6px"}}>
                            <div style={{fontSize:"10px",color:"#555",letterSpacing:"1px",textTransform:"uppercase",marginBottom:"3px"}}>Question</div>
                            <div style={{fontSize:"11px",color:"#555",fontStyle:"italic",marginBottom:"2px",wordBreak:"break-word"}}>{orig.question.slice(0,100)}{orig.question.length>100?"…":""}</div>
                            <div style={{fontSize:"12px",color:"#c8c8e0",wordBreak:"break-word"}}>→ {e.question.slice(0,100)}{e.question.length>100?"…":""}</div>
                          </div>
                        )}
                        {e.answer&&(
                          <div>
                            <div style={{fontSize:"10px",color:"#555",letterSpacing:"1px",textTransform:"uppercase",marginBottom:"3px"}}>Answer</div>
                            <div style={{fontSize:"11px",color:"#555",fontStyle:"italic",marginBottom:"2px",wordBreak:"break-word"}}>{orig.answer.slice(0,100)}{orig.answer.length>100?"…":""}</div>
                            <div style={{fontSize:"12px",color:"#c8c8e0",wordBreak:"break-word"}}>→ {e.answer.slice(0,100)}{e.answer.length>100?"…":""}</div>
                          </div>
                        )}
                      </div>
                    );
                  })}
                </div>
            }
          </div>

          {/* Hidden cards list */}
          {pendingHidden.length>0&&(
          <div style={{background:"#0e0e1a",border:"1px solid #1e1e2e",borderRadius:"10px",padding:"14px"}}>
            <div style={{fontSize:"11px",letterSpacing:"2px",color:"#444",textTransform:"uppercase",marginBottom:"10px"}}>Hidden Cards ({pendingHidden.length})</div>
            <div style={{display:"flex",flexDirection:"column",gap:"6px"}}>
              {pendingHidden.map(c=>(
                <div key={c.id} style={{display:"flex",justifyContent:"space-between",alignItems:"center",gap:"8px"}}>
                  <span style={{fontSize:"12px",color:"#888",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",flex:1}}>Card {c.id} — {c.question.slice(0,50)}…</span>
                  <button onClick={()=>setHidden(h=>h.filter(x=>x!==c.id))} style={{background:"transparent",border:"1px solid #2a2a3a",color:"#555",padding:"4px 8px",borderRadius:"4px",cursor:"pointer",fontSize:"11px",flexShrink:0}}>Restore</button>
                </div>
              ))}
            </div>
          </div>
          )}
        </div>
        );
      })()}

      {/* Edit Modal */}
      {editingCard&&(()=>{
        const current={question:edits[editingCard.id]?.question||editingCard.question,answer:edits[editingCard.id]?.answer||editingCard.answer};
        let q=current.question,a=current.answer;
        return(
        <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.8)",zIndex:200,display:"flex",alignItems:"center",justifyContent:"center",padding:"16px"}}>
          <div style={{background:"#0e0e1a",border:"1px solid #2a2a3a",borderRadius:"12px",padding:"20px",width:"100%",maxWidth:"500px",display:"flex",flexDirection:"column",gap:"12px"}}>
            <div style={{fontSize:"11px",letterSpacing:"2px",color:"#444",textTransform:"uppercase"}}>Edit Card — {editingCard.number}</div>
            <div>
              <div style={{fontSize:"11px",color:"#666",marginBottom:"4px"}}>Question</div>
              <textarea defaultValue={q} onChange={e=>{q=e.target.value}} style={{width:"100%",background:"#080810",border:"1px solid #2a2a3a",color:"#d0d0e8",borderRadius:"6px",padding:"10px",fontSize:"13px",fontFamily:"inherit",resize:"vertical",minHeight:"80px",outline:"none"}}/>
            </div>
            <div>
              <div style={{fontSize:"11px",color:"#666",marginBottom:"4px"}}>Answer</div>
              <textarea defaultValue={a} onChange={e=>{a=e.target.value}} style={{width:"100%",background:"#080810",border:"1px solid #2a2a3a",color:"#d0d0e8",borderRadius:"6px",padding:"10px",fontSize:"13px",fontFamily:"inherit",resize:"vertical",minHeight:"100px",outline:"none"}}/>
            </div>
            <div style={{display:"flex",gap:"8px"}}>
              <button onClick={()=>saveEdit(editingCard.id,q,a)} style={{background:"#06d6a020",border:"1px solid #06d6a050",color:"#06d6a0",padding:"10px 0",borderRadius:"8px",cursor:"pointer",fontSize:"13px",flex:1}}>Save Edit</button>
              <button onClick={()=>setEditingCard(null)} style={{background:"transparent",border:"1px solid #1e1e2e",color:"#555",padding:"10px 16px",borderRadius:"8px",cursor:"pointer",fontSize:"13px"}}>Cancel</button>
            </div>
          </div>
        </div>
        );
      })()}

      {/* Copy Pending Changes Modal */}
      {showPendingCopyModal&&(
        <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.85)",zIndex:200,display:"flex",alignItems:"center",justifyContent:"center",padding:"16px"}}>
          <div style={{background:"#0e0e1a",border:"1px solid #2a2a3a",borderRadius:"12px",padding:"20px",width:"100%",maxWidth:"500px",display:"flex",flexDirection:"column",gap:"12px"}}>
            <div style={{fontSize:"11px",letterSpacing:"2px",color:"#444",textTransform:"uppercase"}}>Pending Changes — Copy to Clipboard</div>
            <textarea readOnly value={pendingSummary} style={{width:"100%",background:"#080810",border:"1px solid #2a2a3a",color:"#a0a0c0",borderRadius:"6px",padding:"10px",fontSize:"12px",fontFamily:"monospace",resize:"vertical",minHeight:"180px",outline:"none",lineHeight:1.6}}/>
            <div style={{display:"flex",gap:"8px"}}>
              <button onClick={()=>navigator.clipboard?.writeText(pendingSummary)} style={{background:"#a78bfa20",border:"1px solid #a78bfa40",color:"#a78bfa",padding:"10px 0",borderRadius:"8px",cursor:"pointer",fontSize:"13px",flex:1}}>Copy to Clipboard</button>
              <button onClick={()=>setShowPendingCopyModal(false)} style={{background:"transparent",border:"1px solid #1e1e2e",color:"#555",padding:"10px 16px",borderRadius:"8px",cursor:"pointer",fontSize:"13px"}}>Close</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}